import { DesktopTRPCProvider } from "@repo/app-trpc/desktop";
import { StrictMode } from "react";
import { createRoot } from "react-dom/client";
import { AppShell } from "./app-shell";

const appOrigin = window.lightfastBridge.appOrigin;

function Root() {
  return (
    <StrictMode>
      <DesktopTRPCProvider baseUrl={appOrigin}>
        <AppShell />
      </DesktopTRPCProvider>
    </StrictMode>
  );
}

const container = document.getElementById("react-root");
if (container) {
  createRoot(container).render(<Root />);
}

import { resolve } from "node:path";
import react from "@vitejs/plugin-react";
import { defineConfig } from "vite";

export default defineConfig({
  root: resolve(import.meta.dirname, "src/renderer"),
  plugins: [react()],
  resolve: {
    // Follow pnpm symlinks to real paths so esbuild's optimizer resolves
    // transitive CJS peers (e.g. copy-anything imported by superjson) via the
    // .pnpm store layout instead of getting stuck in symlinked node_modules
    // that lack the peer.
    preserveSymlinks: false,
  },
  optimizeDeps: {
    include: [
      "@repo/app-trpc/desktop",
      "@repo/app-trpc/react",
      "superjson",
      "sonner",
    ],
  },
  build: {
    outDir: resolve(import.meta.dirname, ".vite/renderer/main_window"),
    emptyOutDir: true,
    rollupOptions: {
      input: resolve(import.meta.dirname, "src/renderer/index.html"),
    },
  },
});

{
  "extends": "@repo/typescript-config/base.json",
